const user = {
  id: 1,
  name: 'Alice',
  address: {
    city: 'Paris',
    country: 'France',
    zip: '75001'
  }
};

// Flat destructuring — only gets top-level values
const { id, name, address } = user;
// address is still an object: { city: 'Paris', country: 'France', zip: '75001' }

// Nested destructuring — reaches into address directly
const { id: userId, name, address: { city, country } } = user;

console.log(userId);   // 1
console.log(name);     // 'Alice'
console.log(city);     // 'Paris'
console.log(country);  // 'France'
// NOTE: 'address' is NOT a variable here — it's a pattern key

const team = {
  name: 'Engineering',
  members: ['Alice', 'Bob', 'Carol']
};

// Extract the team name and the first two members from the array
const { name: teamName, members: [lead, secondLead] } = team;

console.log(teamName);    // 'Engineering'
console.log(lead);        // 'Alice'
console.log(secondLead);  // 'Bob'

const apiResponse = {
  status: 'ok',
  data: [
    { id: 1, title: 'First Post' },
    { id: 2, title: 'Second Post' }
  ]
};

// Extract status and the first post's title in one expression
const { status, data: [{ title: firstPostTitle }] } = apiResponse;

console.log(status);          // 'ok'
console.log(firstPostTitle);  // 'First Post'

const users = [
  { id: 1, name: 'Alice', role: 'admin' },
  { id: 2, name: 'Bob',   role: 'editor' },
  { id: 3, name: 'Carol', role: 'viewer' }
];

// Extract name and role from the first element, just name from the second
const [{ name: firstName, role: firstRole }, { name: secondName }] = users;

console.log(firstName);   // 'Alice'
console.log(firstRole);   // 'admin'
console.log(secondName);  // 'Bob'

const userProfile = {
  name: 'Alice'
  // 'address' is completely absent
};

// Without a default for 'address', this throws:
// const { address: { city } } = userProfile;
// TypeError: Cannot destructure property 'city' of undefined

// With a default empty object for the missing container:
const { address: { city = 'Unknown', zip = '00000' } = {} } = userProfile;

console.log(city); // 'Unknown'
console.log(zip);  // '00000'

const config = {}; // 'servers' property is absent

const { servers: [primaryServer = 'localhost'] = [] } = config;

console.log(primaryServer); // 'localhost'

// A product card receiving a rich product object as a prop
function ProductCard({
  product: {
    id,
    title,
    price,
    images: [primaryImage],
    category: { name: categoryName } = {}
  },
  onAddToCart
}) {
  return (
    <div>
      <img src={primaryImage} alt={title} />
      <h2>{title}</h2>
      <span>{categoryName}</span>
      <p>${price}</p>
      <button onClick={() => onAddToCart(id)}>Add to Cart</button>
    </div>
  );
}

function OrderSummary({ order }) {
  const {
    id: orderId,
    status,
    customer: { name: customerName, email },
    items: [firstItem, ...otherItems],
    totals: { subtotal, tax, total } = {}
  } = order;

  return (
    <section>
      <h2>Order #{orderId} — {status}</h2>
      <p>Customer: {customerName} ({email})</p>
      <p>First item: {firstItem?.name}</p>
      <p>Additional items: {otherItems.length}</p>
      <p>Total: ${total} (incl. ${tax} tax)</p>
    </section>
  );
}

// Hard to read — too much in one expression
const { a: { b: { c: { d: value } } } } = deepObject;

// Better — three readable steps
const { a } = deepObject;
const { b } = a;
const { c: { d: value } } = b;

const user = {}; // no 'address' property

// ❌ TypeError: Cannot destructure property 'city' of undefined
const { address: { city } } = user;

// ✅ Provide a default for the missing container
const { address: { city } = {} } = user; // city is undefined, no crash

const obj = { meta: { version: 2 } };

const { meta: { version } } = obj;

console.log(version); // 2  ✅
console.log(meta);    // ReferenceError: meta is not defined ❌
// 'meta' was used only as a lookup key, not as a variable name

const data = { scores: [90, 85, 78] };

// ❌ Using {} for an array property — scores[0] is undefined
const { scores: { 0: first } } = data; // works but unusual and fragile

// ✅ Correct — use [] to destructure the array
const { scores: [first2] } = data; // first2 = 90
